mapper.select:
SELECT
(
SELECT COUNT(*)
FROM `alert`
WHERE id_device = #{id_device}
AND id_error  = #{id_error}
AND `status`  = 1
AND is_delete = 0
)
+
(
SELECT COUNT(*)
FROM `alert_queue`
WHERE id_device = #{id_device}
AND id_error  = #{id_error}
AND `status`  = 1
AND is_delete = 0
AND is_queue  = 0
)
AS total

